import React, {useContext, useState} from "react";
import InputRow from "../common/InputRow";
import RowDropDown from "../common/RowDropdown";
import {Context} from "../../context";
import {ITodo} from "../../types/todo";

const NewToDoForm = () => {
  const [ newTodoTitle, setNewTodoTitle ] = useState('')
  const [ selectedRoot, setSelectedRoot ] = useState<ITodo|null>(null)

  const handleTitleChange = (val:string) => {
    setNewTodoTitle(val)
  }

  const selectRoot = (todo:ITodo) => {
    setSelectedRoot(todo)
  }

  const addTodo = (e:React.MouseEvent) => {
    e.preventDefault()
    addNewToDo(selectedRoot, newTodoTitle)
  }

  const { getRootTodos, addNewToDo } = useContext(Context)

  return (
    <form className="new-todo-form">
      <RowDropDown label="Root:" options={getRootTodos()} onSelect={selectRoot} selected={selectedRoot} />
      <InputRow value={newTodoTitle} onChange={handleTitleChange} type="text" label="ToDo title:" />
      <button onClick={addTodo}>Add To Do</button>
    </form>
  )
}

export default NewToDoForm