import * as React from 'react';
import * as ReactDOM from "react-dom";

export type ModalProps = {
  children: React.ReactElement;
  onClose: Function
};
export type ModalState = any;

export class Modal extends React.Component<ModalProps, ModalState> {

  container: HTMLDivElement;
  modalRoot: HTMLElement;

  constructor (props: ModalProps) {
    super(props);

    this.modalRoot = document.getElementById("root-modal") || document.createElement("div");
    this.container = document.createElement("div");
  }

  componentDidMount (): void {
    this.modalRoot.appendChild(this.container);
  }

  componentWillUnmount (): void {
    this.modalRoot.removeChild(this.container);
  }

  // @ts-ignore
  handleOnClose = (e):void => {
    const { classList } = e.target
    if (classList.contains("modal-bg" )) {
      this.props.onClose(e)
    }
  }

  render (): React.ReactElement<ModalProps> {

    const modalWrap = (
      <div className="modal-bg" onClick={this.handleOnClose}>
        {this.props.children}
      </div>
    )

    return ReactDOM.createPortal(modalWrap, this.container)
  }
}

export default Modal