import React, {useState} from 'react'
import {ITodo} from "../../types/todo";

interface IProps {
  label: string,
  options: ITodo[],
  selected: ITodo|null,
  onSelect: Function
}

const RowDropDown = (props:IProps) => {
  const [ isOpen, setIsOpen ] = useState(false)
  const { label, options, selected, onSelect } = props

  const toggleDropdown = (e:React.MouseEvent) => {
    e.preventDefault()
    setIsOpen(!isOpen)
  }

  const closeDropdown = () => {
    setIsOpen(false)
  }
  
  const selectOption = (opt:ITodo) => {
    onSelect(opt)
  }

  const DropdownClassList = ['row-dropdown__dropdown', isOpen ? 'open' : null]

  return (
    <div className="row-dropdown form-row">
      <div className="row-dropdown__label">{ label }</div>
      <label className={DropdownClassList.join(' ')}>
        <div className="row-dropdown__dropdown--title-area">
          { selected ? selected.title : null }
        </div>
        <button
          className="row-dropdown__dropdown--arrow"
          onClick={toggleDropdown}
        >
          <i className="far fa-arrow-alt-circle-down" />
        </button>
        <ul className="row-dropdown__dropdown__options">
          {
            options.map(opt => (
              <li key={opt.id} onClick={() => selectOption(opt)}>{opt.title}</li>
            ))
          }
        </ul>
      </label>

    </div>
  )
}

export default RowDropDown