import React from "react";

interface IProps {
  type?:string,
  label?:string
  value:string,
  onChange:Function
}

const InputRow = (props:IProps) => {

  const {
    type = 'test',
    label,
    onChange,
    value
  } = props

  const handleChange = (e:React.ChangeEvent) => {
    //@ts-ignore
    onChange(e.target.value)
  }

  return (
    <label className="input-row form-row">
      <span>{label}</span>
      <input value={value} onChange={handleChange} type={type}/>
    </label>
  )
}

export default InputRow