import React, {useState} from 'react';

import { Context } from '../context'

import Header from './Header/Header';
import List from './List/List';

import '../assets/scss/App.scss';
import {ITodo} from "../types/todo";
import AddToDo from "./AddToDo/AdToDo";

const initState = [
  {
    id: 23534523452354,
    title: 'Wake up',
    isDone: true,
  },
  {
    id: 1,
    title: 'Go shopping',
    isDone: false,
  },
  {
    id: 10,
    parentId: 1,
    title: 'Buy t-shirt',
    isDone: false
  },
  {
    id: 100,
    parentId: 10,
    title: 'Make sure its red',
    isDone: false
  },
  {
    id: 101,
    parentId: 10,
    title: 'Pay for it',
    isDone: false
  }
]

const App = () => {
  const [todos, setTodos] = useState<ITodo[]>(initState)

  const toggleIsDone = (id:number) => {
    setTodos(todos.map(todo => {
      if (todo.id === id) {
        todo.isDone = !todo.isDone
      }
      return todo
    }))
  }

  const removeToDo = (id:number) => {
    setTodos(todos.filter(todo => todo.id !== id))
  }

  const getChildren = (id:number) => {
    return todos.filter(todo => todo.parentId === id)
  }

  const getRootTodos = () => {
    return todos.filter(todo => !todo.parentId)
  }

  const addNewToDo = (parent:ITodo, title:string) => {
    const newTodo:ITodo = {
      id: Date.now(),
      title,
      isDone: false
    }
    if (!!parent) {
      newTodo.parentId = parent.id
    }

    setTodos([newTodo, ...todos])
  }

  return (
    <Context.Provider value={{
      toggleIsDone,
      removeToDo,
      getChildren,
      getRootTodos,
      addNewToDo
    }}>
      <Header />
      <div className="content-wrap">
          <List todos={getRootTodos()}/>

        <AddToDo />
      </div>
    </Context.Provider>
  );
}

export default App;
