import React, { useContext } from "react";
import  { Context } from "../../context";
import {ITodo} from "../../types/todo";
import List from './List'

interface IProps {
  todo: ITodo
}



const ListItem:React.FC<IProps> = ({todo}) => {
  const { toggleIsDone, removeToDo, getChildren } = useContext(Context)

  const { id, title, isDone } = todo

  const iconClass = [
    'fas',
    'fa-trash-alt',
    todo.isDone ? null : 'hidden'
  ].join(' ')

  const children = getChildren(id)

  return (
    <li>
      <div className="list-item-main-content">
        <div>
          <input type="checkbox" checked={isDone} onChange={() => toggleIsDone(id)}/>
          <span>{title}</span>
        </div>
        <i className={iconClass} onClick={() => removeToDo(id)} />
      </div>

      {children.length > 0 && <List todos={children}/>}

    </li>
  )
}

export default ListItem